    platform_print("  display:     ");
    platform_print(framebuffer_get_profile());
    platform_print("\n");

    platform_print("  capability:  ");
    platform_print(capability_is_ready("gui.shell") ? "ready\n" : "blocked\n");

    platform_print("  module deps: ");
