void gshell_break(void) {
    gshell_broken = 1;

    platform_print("Graphical shell break:\n");
    platform_print("  result: broken\n");
}

void gshell_fix(void) {
    gshell_broken = 0;

    if (!gshell_initialized) {
        gshell_init();
    }

    platform_print("Graphical shell fix:\n");
    platform_print("  result: fixed\n");
}